const ships     = $('Get Ships').first().json.data || [];
const contracts = $input.first().json.data || [];

const ship = ships.find(s => s.frame?.symbol === 'FRAME_FRIGATE') || ships[0];
if (!ship) return [{json:{action:'no_ship'}}];

const nav    = ship.nav;
const cargo  = ship.cargo;
const fuel   = ship.fuel;
const status = nav.status;
const wp     = nav.waypointSymbol;
const now    = Date.now();
const flightMode = nav.flightMode || 'CRUISE';

const cdExp = ship.cooldown?.expiration ? new Date(ship.cooldown.expiration).getTime() : 0;
if (cdExp > now) return [{json:{action:'on_cooldown', ship:ship.symbol, remainMs:cdExp-now}}];

if (status === 'IN_TRANSIT') {
  const arr = new Date(nav.route?.arrival).getTime();
  if (arr > now) return [{json:{action:'in_transit', ship:ship.symbol, eta:nav.route.arrival}}];
}

const ASTEROID      = 'X1-UX96-B12';
const DELIVER_WP    = 'X1-UX96-H52';
const FUEL_STATION  = 'X1-UX96-B6';
const MIN_FUEL      = 150;

const activeC  = contracts.find(c => c.accepted && !c.fulfilled);
const pendingC = contracts.find(c => !c.accepted && !c.fulfilled);

if (!activeC && pendingC) {
  return [{json:{action:'accept_contract', ship:ship.symbol, contractId:pendingC.id}}];
}

const term     = activeC?.terms?.deliver?.[0];
const tradeSym = term?.tradeSymbol || 'ALUMINUM_ORE';
const needed   = (term?.unitsRequired||0) - (term?.unitsFulfilled||0);
const haveOre  = cargo.inventory.find(i => i.symbol === tradeSym)?.units || 0;
const cargoPct = cargo.capacity > 0 ? cargo.units / cargo.capacity : 0;
const fuelPct  = fuel.capacity > 0 ? fuel.current / fuel.capacity : 1;
const fuelFull = fuel.current >= fuel.capacity * 0.95;

// DELIVER: only when we actually have contract ore
if (haveOre > 0) {
  const shouldDeliver = wp === DELIVER_WP || cargoPct >= 0.8 || haveOre >= needed;
  if (shouldDeliver) {

    // At delivery waypoint — dock and deliver
    if (wp === DELIVER_WP) {
      if (status === 'IN_ORBIT') return [{json:{action:'dock', ship:ship.symbol}}];
      if (status === 'DOCKED')   return [{json:{action:'deliver', ship:ship.symbol,
          contractId:activeC.id, tradeSymbol:tradeSym, units:haveOre}}];
    }

    // At fuel station — refuel, restore CRUISE, then navigate to delivery
    if (wp === FUEL_STATION) {
      if (status === 'IN_ORBIT') {
        // Already full? Skip the dock cycle and go deliver
        if (fuelFull) return [{json:{action:'navigate', ship:ship.symbol, waypoint:DELIVER_WP, reason:'deliver'}}];
        return [{json:{action:'dock', ship:ship.symbol}}];
      }
      if (status === 'DOCKED') {
        if (!fuelFull)           return [{json:{action:'refuel', ship:ship.symbol}}];
        if (flightMode === 'DRIFT') return [{json:{action:'set_cruise', ship:ship.symbol}}];
        return [{json:{action:'orbit', ship:ship.symbol}}];
      }
    }

    // Need to travel to delivery
    if (status === 'DOCKED') return [{json:{action:'orbit', ship:ship.symbol}}];
    if (status === 'IN_ORBIT') {
      if (fuel.current < MIN_FUEL) {
        if (flightMode !== 'DRIFT')
          return [{json:{action:'set_drift', ship:ship.symbol}}];
        return [{json:{action:'navigate', ship:ship.symbol, waypoint:FUEL_STATION, reason:'refuel'}}];
      }
      return [{json:{action:'navigate', ship:ship.symbol, waypoint:DELIVER_WP, reason:'deliver'}}];
    }
  }
}

// JETTISON: cargo 70%+ full with junk
const junk = cargo.inventory.filter(i => i.symbol !== tradeSym);
if (cargoPct >= 0.7 && junk.length > 0) {
  return junk.map(i => ({json:{action:'jettison', ship:ship.symbol, symbol:i.symbol, units:i.units}}));
}

// NAVIGATE TO ASTEROID
if (wp !== ASTEROID) {
  if (status === 'DOCKED') {
    if (fuelPct < 0.2) return [{json:{action:'refuel', ship:ship.symbol}}];
    if (flightMode === 'DRIFT') return [{json:{action:'set_cruise', ship:ship.symbol}}];
    return [{json:{action:'orbit', ship:ship.symbol}}];
  }
  if (status === 'IN_ORBIT') return [{json:{action:'navigate', ship:ship.symbol,
      waypoint:ASTEROID, reason:'mine'}}];
}

// AT ASTEROID: survey or mine
if (wp === ASTEROID && status === 'IN_ORBIT') {
  const staticData = $getWorkflowStaticData('global');
  const survey = staticData.survey;
  const surveyValid = survey && new Date(survey.expiration).getTime() > now;
  if (!surveyValid) return [{json:{action:'survey', ship:ship.symbol}}];
  return [{json:{action:'mine_survey', ship:ship.symbol, survey}}];
}

if (wp === ASTEROID && status === 'DOCKED') {
  return [{json:{action:'orbit', ship:ship.symbol}}];
}

return [{json:{action:'idle', ship:ship.symbol, status, wp}}];

const staticData = $getWorkflowStaticData('global');
const result = $input.first().json;
const surveys = result.data?.surveys || [];

// Prefer survey that has contract ore deposits
const contractOre = 'ALUMINUM_ORE';
const best = surveys.find(s => s.deposits?.some(d => d.symbol === contractOre)) || surveys[0];

if (best) {
  staticData.survey = best;
  const ores = best.deposits.map(d => d.symbol).join(', ');
  return [{json:{stored:true, signature:best.signature, ores, expiration:best.expiration}}];
}
return [{json:{stored:false}}];

